# ===============================================# CONFIGURAES DO USURIO# ===============================================SSID = "MultiTec"SENHA = "26041989Ab"#URL_API = "https://alertasat.onrender.com"URL_API = "https://obsat.org.br/teste_post/envio_bipes.php"# ===============================================# IMPORTAES# ===============================================import osimport timeimport mathimport machinefrom machine import Pin, I2C, ADC, PWMimport dhtfrom bmp280 import *import CCS811from mpu9250 import MPU9250import urequestsimport ujsonimport network# ===============================================# DEFINIO DE PORTAS# ===============================================BATERIA = 35# LEDsLEDSA = 13LEDSB = 5RGB1RED = 14RGB1GREEN = 27RGB1BLUE = 26RGB2RED = 4RGB2GREEN = 32RGB2BLUE = 33# BuzzerBUZZER = 25# SensoresDHT22 = 2SENSORES = I2C(scl=Pin(22), sda=Pin(21))# ===============================================# INICIALIZAO DE SENSORES# ===============================================sDHT22 = dht.DHT22(Pin(DHT22))sMPU9250 = MPU9250(SENSORES)sBMP280 = BMP280(SENSORES)sBMP280.use_case(BMP280_CASE_WEATHER)sBMP280.oversample(BMP280_OS_HIGH)sCCS811 = CCS811.CCS811(i2c=SENSORES, addr=90)sBateria = ADC(Pin(BATERIA))sBateria.atten(ADC.ATTN_11DB)sBateria.width(ADC.WIDTH_9BIT)# ===============================================# VARIVEIS GLOBAIS# ===============================================maxHistorico = 10historico = {    "dht Temperatura (*C)": [],    "dht Umidade (UR)": [],    "mpu Aceleracao X (m/s^2)": [],    "mpu Aceleracao Y (m/s^2)": [],    "mpu Aceleracao Z (m/s^2)": [],    "mpu Giroscopio X (graus/seg)": [],    "mpu Giroscopio Y (graus/seg)": [],    "mpu Giroscopio Z (graus/seg)": [],    "mpu Magnetismo X (microteslas)": [],    "mpu Magnetismo Y (microteslas)": [],    "mpu Magnetismo Z (microteslas)": [],    "bmp Pressao (hPa)": [],    "bmp Temperatura (*C)": [],    "ccs CO2 (ppm)": [],    "ccs TVOC (ppb)": [],    "Altitude (m)": [],    "Bateria (%)": []}primeiro_envio = Truenovo_arquivo = ""sta = network.WLAN(network.STA_IF)# ===============================================# FUNCOES AUXILIARES# ===============================================def digitalWrite(pin, valor):    led = Pin(pin, Pin.OUT)    led.value(1 if valor else 0)def apitarBuzzer(ms):    buzzer = PWM(Pin(BUZZER), freq=1200, duty=512)    time.sleep(ms / 1000)    buzzer.deinit()def getMediaMovel(array):    if not array:        return -999    return sum(array) / len(array)def calcPercentualBateria(valor):    minimo = 266    maximo = 312    percentual = (valor - minimo) * 100 / (maximo - minimo)    if percentual < 1:        percentual = 1    elif percentual > 100:        percentual = 100    return percentual# ===============================================# FUNCAO: ATUALIZAR SENSORES# ===============================================def atualizarSensores():    global dhtTemperatura, dhtUmidade    global mpuAceleracaoX, mpuAceleracaoY, mpuAceleracaoZ    global mpuGiroscopioX, mpuGiroscopioY, mpuGiroscopioZ    global mpuMagnetismoX, mpuMagnetismoY, mpuMagnetismoZ    global bmpPressao, bmpTemperatura, ccsCo2, ccsTvoc    global altitude, bateria    try:        sDHT22.measure()        dhtTemperatura = sDHT22.temperature()        dhtUmidade = sDHT22.humidity()    except:        dhtTemperatura = -999        dhtUmidade = -999        print("Erro ao calibrar DHT22")    try:        mpuGiroscopioX, mpuGiroscopioY, mpuGiroscopioZ = sMPU9250.gyro        mpuAceleracaoX, mpuAceleracaoY, mpuAceleracaoZ = sMPU9250.acceleration        mpuMagnetismoX, mpuMagnetismoY, mpuMagnetismoZ = sMPU9250.magnetic    except:        mpuAceleracaoX = mpuAceleracaoY = mpuAceleracaoZ = -999        mpuGiroscopioX = mpuGiroscopioY = mpuGiroscopioZ = -999        mpuMagnetismoX = mpuMagnetismoY = mpuMagnetismoZ = -999        print("Erro ao calibrar MPU9250")    try:        sBMP280.normal_measure()        bmpPressao = sBMP280.pressure / 100        bmpTemperatura = sBMP280.temperature    except:        bmpPressao = bmpTemperatura = -999        print("Erro ao calibrar BMP280")    try:        for i in range(10):            if sCCS811.data_ready():                sCCS811.put_envdata(dhtUmidade, bmpTemperatura)                ccsCo2 = sCCS811.eCO2                ccsTvoc = sCCS811.tVOC                print(ccsCo2);                print(ccsTvoc);                break            print("Calibrando CCS811...")            time.sleep(0.1)            if i == 9:                print("Falha na calibrao CCS811")                ccsCo2 = ccsTvoc = -999    except Exception as e:      print("Erro ao calibrar CCS811:", e)      ccsCo2 = ccsTvoc = -999        pressao_nivel_mar = 1013.25    altitude = 44330 * (1 - (bmpPressao / pressao_nivel_mar) ** (1/5.255))    leitura_bat = sBateria.read()    bateria = calcPercentualBateria(leitura_bat)# ===============================================# HISTRICO DE DADOS# ===============================================def atualizarHistorico():    global historico    #pra evitar erro, caso a medicao atual falhar, substituir o valor atual pela media do historico    novos_dados = {      "dht Temperatura (*C)": round(getMediaMovel(historico["dht Temperatura (*C)"]), 2) if dhtTemperatura == -999 else dhtTemperatura,      "dht Umidade (UR)": round(getMediaMovel(historico["dht Umidade (UR)"]), 2) if dhtUmidade == -999 else dhtUmidade,      "mpu Aceleracao X (m/s^2)": round(getMediaMovel(historico["mpu Aceleracao X (m/s^2)"]), 2) if mpuAceleracaoX == -999 else mpuAceleracaoX,      "mpu Aceleracao Y (m/s^2)": round(getMediaMovel(historico["mpu Aceleracao Y (m/s^2)"]), 2) if mpuAceleracaoY == -999 else mpuAceleracaoY,      "mpu Aceleracao Z (m/s^2)": round(getMediaMovel(historico["mpu Aceleracao Z (m/s^2)"]), 2) if mpuAceleracaoZ == -999 else mpuAceleracaoZ,      "mpu Giroscopio X (graus/seg)": round(getMediaMovel(historico["mpu Giroscopio X (graus/seg)"]), 2) if mpuGiroscopioX == -999 else mpuGiroscopioX,      "mpu Giroscopio Y (graus/seg)": round(getMediaMovel(historico["mpu Giroscopio Y (graus/seg)"]), 2) if mpuGiroscopioY == -999 else mpuGiroscopioY,      "mpu Giroscopio Z (graus/seg)": round(getMediaMovel(historico["mpu Giroscopio Z (graus/seg)"]), 2) if mpuGiroscopioZ == -999 else mpuGiroscopioZ,      "mpu Magnetismo X (microteslas)": round(getMediaMovel(historico["mpu Magnetismo X (microteslas)"]), 2) if mpuMagnetismoX == -999 else mpuMagnetismoX,      "mpu Magnetismo Y (microteslas)": round(getMediaMovel(historico["mpu Magnetismo Y (microteslas)"]), 2) if mpuMagnetismoY == -999 else mpuMagnetismoY,      "mpu Magnetismo Z (microteslas)": round(getMediaMovel(historico["mpu Magnetismo Z (microteslas)"]), 2) if mpuMagnetismoZ == -999 else mpuMagnetismoZ,      "bmp Pressao (hPa)": round(getMediaMovel(historico["bmp Pressao (hPa)"]), 2) if bmpPressao == -999 else bmpPressao,      "bmp Temperatura (*C)": round(getMediaMovel(historico["bmp Temperatura (*C)"]), 2) if bmpTemperatura == -999 else bmpTemperatura,      "ccs CO2 (ppm)": round(getMediaMovel(historico["ccs CO2 (ppm)"]), 2) if ccsCo2 == -999 else ccsCo2,      "ccs TVOC (ppb)": round(getMediaMovel(historico["ccs TVOC (ppb)"]), 2) if ccsTvoc == -999 else ccsTvoc,      "Altitude (m)": round(getMediaMovel(historico["Altitude (m)"]), 2) if altitude == -999 else altitude,      "Bateria (%)": round(getMediaMovel(historico["Bateria (%)"]), 2) if bateria == -999 else bateria    }    for chave, valor in novos_dados.items():      historico[chave].append(valor)      if len(historico[chave]) > maxHistorico:        historico[chave].pop(0)# ===============================================# FUNCES DE REDE E ARMAZENAMENTO# ===============================================def conectarWifi():    global sta    sta.active(True)    sta.connect(SSID, SENHA)    for i in range(11):        if sta.isconnected():            print("Wi-Fi conectado:", sta.ifconfig())            return        time.sleep(1)    print("Falha ao conectar Wi-Fi")    sta.active(False)def enviarReqHTTP(url):    global primeiro_envio, sta    if not sta.isconnected():        conectarWifi()    if sta.isconnected():        try:                        metodo = "GET"             print("\n--- Enviando dados HTTP ---")            #print("Mtodo:", metodo)            #print("Ordem de envio:", chaves_ordenadas)            #print("Contedo:", json_texto)                        teste={              "equipe": 1,              "bateria": round(getMediaMovel(historico["Bateria (%)"]), 2),              "temperatura": round(getMediaMovel(historico["bmp Temperatura (*C)"]), 2),              "pressao": round(getMediaMovel(historico["bmp Pressao (hPa)"]), 2),              "giroscopio": [round(getMediaMovel(historico["mpu Giroscopio X (graus/seg)"]), 2), round(getMediaMovel(historico["mpu Giroscopio Y (graus/seg)"]), 2), round(getMediaMovel(historico["mpu Giroscopio Z (graus/seg)"]), 2)],              "acelerometro": [round(getMediaMovel(historico["mpu Aceleracao X (m/s^2)"]), 2), round(getMediaMovel(historico["mpu Aceleracao Y (m/s^2)"]), 2), round(getMediaMovel(historico["mpu Aceleracao Z (m/s^2)"]), 2)],              "payload": [                "Alt:{}m Umi:{}UR Mag:{},{},{}micT CO2:{}ppm TVoc:{}ppb".format(round(getMediaMovel(historico["Altitude (m)"]), 2), round(getMediaMovel(historico["dht Umidade (UR)"]), 2), round(getMediaMovel(historico["mpu Magnetismo X (microteslas)"]), 2), round(getMediaMovel(historico["mpu Magnetismo Y (microteslas)"]), 2) , round(getMediaMovel(historico["mpu Magnetismo Z (microteslas)"]), 2), round(getMediaMovel(historico["ccs CO2 (ppm)"]), 2), round(getMediaMovel(historico["ccs TVOC (ppb)"]), 2) )              ]            }                                    testejson = ujson.dumps(teste)            resposta = urequests.request(                method=metodo,                url=url,                data=testejson,                headers={"Content-Type": "application/json"}            )            print("Status:", resposta.status_code)            resposta.close()            primeiro_envio = False                        digitalWrite(LEDSB, True);            apitarBuzzer(500);            digitalWrite(LEDSB, False);        except Exception as e:            print("Erro ao enviar dados HTTP:", e)gravandoSD = True;primeiroValorL3 = Truedef atualizarValoresSDCard():    global novo_arquivo, historico, primeiroValorL3    try:        arquivo = open(novo_arquivo, 'a')        for chave in sorted(historico.keys()):          if primeiroValorL3:            valores= historico[chave]            arquivo.write(str(round(getMediaMovel(valores), 2)))            primeiroValorL3=False          else:            valores= historico[chave]            arquivo.write(',' + str(round(getMediaMovel(valores), 2)))                    arquivo.close()                print("Txt atualizado.")        digitalWrite(LEDSA, True);        apitarBuzzer(500);        digitalWrite(LEDSA, False);                      except:        print("Falha ao gravar no SD")        global gravandoSD;        gravandoSD = False;        #apagando leds que podem iniciar acesosallLeds = [LEDSA,           LEDSB,           RGB1RED,           RGB1GREEN,           RGB1BLUE,           RGB2RED,           RGB2GREEN,           RGB2BLUE]for led in allLeds:  digitalWrite(led, False);  # ===============================================# INICIALIZAO DO SD CARD# ===============================================try:  sdcard = machine.SDCard(    slot=2, width=1, cd=None, wp=None,    sck=Pin(18), miso=Pin(19), mosi=Pin(23),    cs=Pin(15), freq=4000000  )  os.mount(sdcard, '/sd')  print("SD montado com sucesso!")except Exception as e:    print("Falha ao montar SD:", e)    gravandoSD= False;pasta = '/sd/decolagens'try:    os.mkdir(pasta)except:    passtry:  arquivos = os.listdir(pasta)  numeros = [int(f.replace('decolagem', '').replace('.txt', '')) for f in arquivos if f.startswith('decolagem')]  novo_num = max(numeros) + 1 if numeros else 1  novo_arquivo = f"{pasta}/decolagem{novo_num}.txt"  with open(novo_arquivo, 'w') as arq:    arq.write("Comentario/Descricao:\n")        primeiroValor = True    for chave in sorted(historico.keys()):      if primeiroValor:        arq.write(chave)        primeiroValor= False      else:        arq.write(',' + chave)    arq.write('\n')    arq.close()    print("Novo arquivo criado:", novo_arquivo)except:  print("Falha ao gravar no SD")  gravandoSD = False;    #por garantia de inicio, tenta conectar ao wifi 5 vezes, se nao for, soh daqui a 4 minutos.digitalWrite(RGB2BLUE, True);conectarWifi();if not sta.isconnected():  digitalWrite(RGB2GREEN, True);  conectarWifi();if not sta.isconnected():  digitalWrite(RGB2RED, True);  conectarWifi();if not sta.isconnected():  digitalWrite(RGB2RED, True);  conectarWifi();digitalWrite(RGB2BLUE, False);digitalWrite(RGB2RED, False);digitalWrite(RGB2GREEN, False);# ===============================================# LOOP PRINCIPAL # ===============================================#leitura inicialatualizarSensores();atualizarHistorico();atualizarValoresSDCard();enviarReqHTTP(URL_API)segundosAnt6seg = time.ticks_ms()/1000  #ATUALIZAR LEITURAsegundosAnt10seg = time.ticks_ms()/1000 #EMITIR DIAGNOSTICOsegundosAnt1min = time.ticks_ms()/1000  #ENVIO SDsegundosAnt4min = time.ticks_ms()/1000  #ENVIO WIFIwhile True:    segundos = time.ticks_ms()/1000 #segundos desde que o esp iniciou        if (segundos-segundosAnt4min)>= (4*60): #4min, 1min, 10seg, 6seg simultaneamente      segundosAnt6seg = time.ticks_ms()/1000  #ATUALIZAR LEITURA      segundosAnt10seg = time.ticks_ms()/1000 #EMITIR DIAGNOSTICO      segundosAnt1min = time.ticks_ms()/1000  #ENVIO SD      segundosAnt4min = time.ticks_ms()/1000  #ENVIO WIFI            #4min - primeiro por ser mais importante      enviarReqHTTP(URL_API)                  #10seg e 1min      if gravandoSD:          atualizarValoresSDCard() #1min                    digitalWrite(RGB1GREEN, True);          digitalWrite(RGB1RED, False);      else:        digitalWrite(RGB1GREEN, False);        digitalWrite(RGB1RED, True);              if sta.isconnected():        digitalWrite(RGB2GREEN, True);        digitalWrite(RGB2RED, False);              else:        digitalWrite(RGB2GREEN, False);        digitalWrite(RGB2RED, True);                      if round(getMediaMovel(historico["Bateria (%)"]), 2) <= 35:        apitarBuzzer(100);        time.sleep(0.1);        apitarBuzzer(100);      else:        time.sleep(1)              digitalWrite(RGB1RED, False);      digitalWrite(RGB1GREEN, False);      digitalWrite(RGB2RED, False);      digitalWrite(RGB2GREEN, False);                  #6seg - menos importante      atualizarSensores()      atualizarHistorico()                      elif ((segundos-segundosAnt1min) >= 60): #1min, 10seg, 6seg simultaneamente      segundosAnt6seg = time.ticks_ms()/1000  #ATUALIZAR LEITURA      segundosAnt10seg = time.ticks_ms()/1000 #EMITIR DIAGNOSTICO      segundosAnt1min = time.ticks_ms()/1000  #ENVIO SD                  #10seg e 1min      if gravandoSD:          atualizarValoresSDCard() #1min                    digitalWrite(RGB1GREEN, True);          digitalWrite(RGB1RED, False);      else:        digitalWrite(RGB1GREEN, False);        digitalWrite(RGB1RED, True);              if sta.isconnected():        digitalWrite(RGB2GREEN, True);        digitalWrite(RGB2RED, False);              else:        digitalWrite(RGB2GREEN, False);        digitalWrite(RGB2RED, True);                      if round(getMediaMovel(historico["Bateria (%)"]), 2) <= 5:        apitarBuzzer(100);        time.sleep(0.1);        apitarBuzzer(100);      else:        time.sleep(1)              digitalWrite(RGB1RED, False);      digitalWrite(RGB1GREEN, False);      digitalWrite(RGB2RED, False);      digitalWrite(RGB2GREEN, False);                  #6seg      atualizarSensores()      atualizarHistorico()            elif (segundos-segundosAnt6seg) >= 6: # a cada 6 segundos        segundosAnt6seg = time.ticks_ms()/1000                intervaloServer = segundos-segundosAnt4min;        intervaloSD = segundos-segundosAnt1min;        print("faltam {}m{}s para enviar para o server".format( int(3-intervaloServer//60), int(59-(intervaloServer-(intervaloServer//60)*60))) );        print("faltam {}s para enviar para o SD".format(int(59-intervaloSD)));                #print(segundos-segundosAnt4min)        atualizarSensores()        atualizarHistorico()                          elif (segundos-segundosAnt10seg)>= (10): #a cada 10 segundos      segundosAnt10seg = time.ticks_ms()/1000            if gravandoSD:        digitalWrite(RGB1GREEN, True);        digitalWrite(RGB1RED, False);      else:        digitalWrite(RGB1GREEN, False);        digitalWrite(RGB1RED, True);              if sta.isconnected():        digitalWrite(RGB2GREEN, True);        digitalWrite(RGB2RED, False);              else:        digitalWrite(RGB2GREEN, False);        digitalWrite(RGB2RED, True);                      if round(getMediaMovel(historico["Bateria (%)"]), 2) <= 5:        apitarBuzzer(100);        time.sleep(0.1);        apitarBuzzer(100);      else:        time.sleep(1)              digitalWrite(RGB1RED, False);      digitalWrite(RGB1GREEN, False);      digitalWrite(RGB2RED, False);      digitalWrite(RGB2GREEN, False);      